                    algorithm.Equals("none", StringComparison.OrdinalIgnoreCase))
                {
                    _logger.LogWarning("Token uses 'none' or empty algorithm — rejected.");
                    return false;
                }

                // Check against our explicit allowlist
                if (!AllowedAlgorithms.Contains(algorithm, StringComparer.Ordinal))
                {
                    _logger.LogWarning(
                        "Token uses disallowed algorithm '{Algorithm}'. Allowed: [{Allowed}].",
                        algorithm,
                        string.Join(", ", AllowedAlgorithms));
                    return false;
                }

                // Reject tokens with the 'jku', 'jwk', 'x5u', 'x5c' headers that could be used
                // for key injection attacks
