                    if (jwtToken.Header.ContainsKey(header))
                    {
                        _logger.LogWarning(
                            "Token contains dangerous header '{Header}' — rejected.",
                            header);
                        return false;
                    }
                }

                return true;
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Failed to pre-validate token algorithm.");
                return false;
            }
