        /// <summary>
        /// Post-validation checks on the validated security token.
        /// </summary>
        private bool PostValidateToken(SecurityToken validatedToken)
        {
            if (validatedToken is not JwtSecurityToken jwtToken)
            {
                _logger.LogWarning("Validated token is not a JwtSecurityToken.");
                return false;
            }

            // Double-check the algorithm after validation (defense-in-depth)
            if (!AllowedAlgorithms.Contains(jwtToken.Header.Alg, StringComparer.Ordinal))
            {
                _logger.LogWarning(
                    "Post-validation: token algorithm '{Algorithm}' is not in the allowlist.",
                    jwtToken.Header.Alg);
                return false;
            }

            // Verify the signing key was actually used
            if (jwtToken.SignatureAlgorithm == null ||
                jwtToken.SignatureAlgorithm.Equals("none", StringComparison.OrdinalIgnoreCase))
            {
                _logger.LogWarning("Post-validation: token has no valid signature algorithm.");
                return false;
            }

            // Ensure the token has a subject claim
            var subClaim = jwtToken.Claims.FirstOrDefault(c =>
                c.Type == JwtRegisteredClaimNames.Sub ||
                c.Type == ClaimTypes.NameIdentifier);

            if (subClaim == null || string.IsNullOrWhiteSpace(subClaim.Value))
            {
                _logger.LogWarning("Post-validation: token is missing a 'sub' claim.");
                return false;
            }

            // Ensure the token has a jti (JWT ID) claim for potential replay detection
            var jtiClaim = jwtToken.Claims.FirstOrDefault(c => c.Type == JwtRegisteredClaimNames.Jti);
            if (jtiClaim == null || string.IsNullOrWhiteSpace(jtiClaim.Value))
            {
                _logger.LogDebug(
                    "Token does not contain a 'jti' claim. Consider requiring jti for replay protection.");
            }

            // Validate issued-at is not in the future (with clock skew tolerance)
            var iatClaim = jwtToken.Claims.FirstOrDefault(c => c.Type == JwtRegisteredClaimNames.Iat);
            if (iatClaim != null && long.TryParse(iatClaim.Value, out var iatEpoch))
            {
                var issuedAt = DateTimeOffset.FromUnixTimeSeconds(iatEpoch);
                var maxFutureTime = DateTimeOffset.UtcNow.Add(_options.ClockSkew);

                if (issuedAt > maxFutureTime)
                {
                    _logger.LogWarning(
                        "Post-validation: token 'iat' claim ({IssuedAt}) is in the future.",
                        issuedAt);
                    return false;
                }
            }

            return true;
        }

        /// <summary>
        /// Writes a generic unauthorized response without leaking internal details.
        /// </summary>
        private static async Task WriteUnauthorizedResponse(HttpContext context, string message)
        {
            context.Response.Headers.Append("WWW-Authenticate", "Bearer");
            context.Response.ContentType = "application/json";
            await context.Response.WriteAsync(
                System.Text.Json.JsonSerializer.Serialize(new
                {
                    error = "unauthorized",
                    message
                }));
        }
