    /// <summary>
    /// Extension methods for registering the JWT authentication middleware.
    /// </summary>
    public static class JwtAuthenticationMiddlewareExtensions
    {
        /// <summary>
        /// Adds JWT authentication services to the service collection.
        /// </summary>
        public static IServiceCollection AddJwtAuthenticationMiddleware(
            this IServiceCollection services,
            IConfiguration configuration)
        {
            services.Configure<JwtAuthenticationOptions>(
                configuration.GetSection(JwtAuthenticationOptions.SectionName));

            return services;
        }

        /// <summary>
        /// Adds JWT authentication services with explicit options configuration.
        /// </summary>
        public static IServiceCollection AddJwtAuthenticationMiddleware(
            this IServiceCollection services,
            Action<JwtAuthenticationOptions> configureOptions)
        {
            services.Configure(configureOptions);
            return services;
        }

        /// <summary>
        /// Adds the JWT authentication middleware to the pipeline.
        /// Should be called before UseAuthorization().
        /// </summary>
        public static IApplicationBuilder UseJwtAuthenticationMiddleware(
            this IApplicationBuilder app)
        {
            return app.UseMiddleware<JwtAuthenticationMiddleware>();
        }
    }

    /// <summary>
    /// Helper class for generating JWT tokens (for testing/development purposes).
    /// In production, token generation should be in a separate identity service.
    /// </summary>
    public static class JwtTokenGenerator
    {
        /// <summary>
        /// Generates a secure JWT token with all required claims.
        /// </summary>
        public static string GenerateToken(
            string secretKey,
            string issuer,
            string audience,
            string subject,
            string[] roles = null,
            IDictionary<string, string> additionalClaims = null,
            TimeSpan? expiration = null)
        {
            var keyBytes = Encoding.UTF8.GetBytes(secretKey);
            var securityKey = new SymmetricSecurityKey(keyBytes);

            // Explicitly specify HS256 — never allow the library to choose
            var credentials = new SigningCredentials(securityKey, SecurityAlgorithms.HmacSha256);

            var claims = new List<Claim>
            {
                new Claim(JwtRegisteredClaimNames.Sub, subject),
                new Claim(JwtRegisteredClaimNames.Jti, Guid.NewGuid().ToString()),
                new Claim(JwtRegisteredClaimNames.Iat,
                    DateTimeOffset.UtcNow.ToUnixTimeSeconds().ToString(),
                    ClaimValueTypes.Integer64)
            };

            if (roles != null)
            {
                foreach (var role in roles)
                {
                    claims.Add(new Claim(ClaimTypes.Role, role));
                }
            }

            if (additionalClaims != null)
            {
                foreach (var kvp in additionalClaims)
                {
                    claims.Add(new Claim(kvp.Key, kvp.Value));
                }
            }

            var tokenExpiration = expiration ?? TimeSpan.FromHours(1);
            var now = DateTime.UtcNow;

            var tokenDescriptor = new SecurityTokenDescriptor
            {
                Subject = new ClaimsIdentity(claims),
                Issuer = issuer,
                Audience = audience,
                NotBefore = now,
                IssuedAt = now,
                Expires = now.Add(tokenExpiration),
                SigningCredentials = credentials
            };

            var tokenHandler = new JwtSecurityTokenHandler
            {
                MapInboundClaims = false
            };

            var token = tokenHandler.CreateToken(tokenDescriptor);
            return tokenHandler.WriteToken(token);
        }
    }
